import Foundation

class AnalyticsLogger {
    static let shared = AnalyticsLogger()
    
    private init() {}
    
    func logAuthenticationFlow(step: String, userId: String? = nil, email: String? = nil) {
        let message = "Authentication Flow - Step: \(step)"
        if let userId = userId {
            NSLog("\(message), User ID: \(userId)")
        } else if let email = email {
            NSLog("\(message), Email: \(email)")
        }
    }
    
    func logAPICall(method: String, endpoint: String, payload: [String: Any]? = nil, response: [String: Any]? = nil) {
        var message = "API Call - Method: \(method), Endpoint: \(endpoint)"
        if let payload = payload {
            message += ", Payload: \(String(describing: payload))"
        }
        if let response = response {
            message += ", Response: \(String(describing: response))"
        }
        NSLog(message)
    }
    
    func logUserDataChange(key: String, oldValue: Any?, newValue: Any?) {
        let message = "User Data Change - Key: \(key), Old Value: \(String(describing: oldValue)), New Value: \(String(describing: newValue))"
        NSLog(message)
    }
    
    func logError(condition: String, error: Error? = nil) {
        var message = "Error Condition: \(condition)"
        if let error = error {
            message += ", Error Description: \(error.localizedDescription)"
        }
        NSLog(message)
    }
}

